package com.careeros.prompt.application;import org.junit.jupiter.api.Test;import java.util.*;import static org.assertj.core.api.Assertions.*;class PromptTemplateServiceTest{@Test void resolvesEveryPlaceholderIncludingSoftSkills(){String value=new PromptTemplateService().render(Map.of("master_resume","Java engineer","job_title","Staff Engineer","job_description","Platform","match_explanation","Strong","notes","Local","skills","Java","soft_skills","mentoring"));assertThat(value).contains("mentoring","Java engineer").doesNotContain("{soft_skills}","{master_resume}");}@Test void rejectsMissingVariables(){assertThatThrownBy(()->new PromptTemplateService().render(Map.of())).isInstanceOf(IllegalArgumentException.class).hasMessageContaining("placeholder");}}
